function dismiss() {
    $("#modal\\.flashes").empty()
    $("#modal").modal('hide')
    $("#resultsTable").dataTable().DataTable().clear().draw()
}

// Deletes a campaign after prompting the user
function deleteCampaign() {
    Swal.fire({
        title: "Are you sure?",
        text: "This will delete the campaign. This can't be undone!",
        type: "warning",
        animation: false,
        showCancelButton: true,
        confirmButtonText: "Delete Campaign",
        confirmButtonColor: "#428bca",
        reverseButtons: true,
        allowOutsideClick: false,
        showLoaderOnConfirm: true,
        preConfirm: function () {
            return new Promise(function (resolve, reject) {
                api.campaignId.delete(campaign.id)
                    .success(function (msg) {
                        resolve()
                    })
                    .error(function (data) {
                        reject(data.responseJSON.message)
                    })
            })
        }
    }).then(function (result) {
        if(result.value){
            Swal.fire(
                'Campaign Deleted!',
                'This campaign has been deleted!',
                'success'
            );
        }
        $('button:contains("OK")').on('click', function () {
            location.href = '/campaigns'
        })
    })
}

// Completes a campaign after prompting the user
function completeCampaign() {
    Swal.fire({
        title: "Are you sure?",
        text: "Gophish will stop processing events for this campaign",
        type: "warning",
        animation: false,
        showCancelButton: true,
        confirmButtonText: "Complete Campaign",
        confirmButtonColor: "#428bca",
        reverseButtons: true,
        allowOutsideClick: false,
        showLoaderOnConfirm: true,
        preConfirm: function () {
            return new Promise(function (resolve, reject) {
                api.campaignId.complete(campaign.id)
                    .success(function (msg) {
                        resolve()
                    })
                    .error(function (data) {
                        reject(data.responseJSON.message)
                    })
            })
        }
    }).then(function (result) {
        if (result.value){
            Swal.fire(
                'Campaign Completed!',
                'This campaign has been completed!',
                'success'
            );
            $('#complete_button')[0].disabled = true;
            $('#complete_button').text('Completed!')
            doPoll = false;
        }
    })
}

// Exports campaign results as a CSV file
function exportAsCSV(scope) {
    exportHTML = $("#exportButton").html()
    var csvScope = null
    var filename = campaign.name + ' - ' + capitalize(scope) + '.csv'
    switch (scope) {
        case "results":
            csvScope = campaign.results
            break;
        case "events":
            csvScope = campaign.timeline
            break;
    }
    if (!csvScope) {
        return
    }
    $("#exportButton").html('<i class="fa fa-spinner fa-spin"></i>')
    var csvString = Papa.unparse(csvScope, {
        'escapeFormulae': true
    })
    var csvData = new Blob([csvString], {
        type: 'text/csv;charset=utf-8;'
    });
    if (navigator.msSaveBlob) {
        navigator.msSaveBlob(csvData, filename);
    } else {
        var csvURL = window.URL.createObjectURL(csvData);
        var dlLink = document.createElement('a');
        dlLink.href = csvURL;
        dlLink.setAttribute('download', filename)
        document.body.appendChild(dlLink)
        dlLink.click();
        document.body.removeChild(dlLink)
    }
    $("#exportButton").html(exportHTML)
}

function replay(event_idx) {
    request = campaign.timeline[event_idx]
    details = JSON.parse(request.details)
    url = null
    form = $('<form>').attr({
        method: 'POST',
        target: '_blank',
    })
    /* Create a form object and submit it */
    $.each(Object.keys(details.payload), function (i, param) {
        if (param == "rid") {
            return true;
        }
        if (param == "__original_url") {
            url = details.payload[param];
            return true;
        }
        $('<input>').attr({
            name: param,
        }).val(details.payload[param]).appendTo(form);
    })
    /* Ensure we know where to send the user */
    // Prompt for the URL
    Swal.fire({
        title: 'Where do you want the credentials submitted to?',
        input: 'text',
        showCancelButton: true,
        inputPlaceholder: "http://example.com/login",
        inputValue: url || "",
        inputValidator: function (value) {
            return new Promise(function (resolve, reject) {
                if (value) {
                    resolve();
                } else {
                    reject('Invalid URL.');
                }
            });
        }
    }).then(function (result) {
        if (result.value){
            url = result.value
            submitForm()
        }
    })
    return
    submitForm()

    function submitForm() {
        form.attr({
            action: url
        })
        form.appendTo('body').submit().remove()
    }
}

/**
 * Returns an HTML string that displays the OS and browser that clicked the link
 * or submitted credentials.
 * 
 * @param {object} event_details - The "details" parameter for a campaign
 *  timeline event
 * 
 */
var renderDevice = function (event_details) {
    var ua = UAParser(details.browser['user-agent'])
    var detailsString = '<div class="timeline-device-details">'

    var deviceIcon = 'laptop'
    if (ua.device.type) {
        if (ua.device.type == 'tablet' || ua.device.type == 'mobile') {
            deviceIcon = ua.device.type
        }
    }

    var deviceVendor = ''
    if (ua.device.vendor) {
        deviceVendor = ua.device.vendor.toLowerCase()
        if (deviceVendor == 'microsoft') deviceVendor = 'windows'
    }

    var deviceName = 'Unknown'
    if (ua.os.name) {
        deviceName = ua.os.name
        if (deviceName == "Mac OS") {
            deviceVendor = 'apple'
        } else if (deviceName == "Windows") {
            deviceVendor = 'windows'
        }
        if (ua.device.vendor && ua.device.model) {
            deviceName = ua.device.vendor + ' ' + ua.device.model
        }
    }

    if (ua.os.version) {
        deviceName = deviceName + ' (OS Version: ' + ua.os.version + ')'
    }

    deviceString = '<div class="timeline-device-os"><span class="fa fa-stack">' +
        '<i class="fa fa-' + escapeHtml(deviceIcon) + ' fa-stack-2x"></i>' +
        '<i class="fa fa-vendor-icon fa-' + escapeHtml(deviceVendor) + ' fa-stack-1x"></i>' +
        '</span> ' + escapeHtml(deviceName) + '</div>'

    detailsString += deviceString

    var deviceBrowser = 'Unknown'
    var browserIcon = 'info-circle'
    var browserVersion = ''

    if (ua.browser && ua.browser.name) {
        deviceBrowser = ua.browser.name
        // Handle the "mobile safari" case
        deviceBrowser = deviceBrowser.replace('Mobile ', '')
        if (deviceBrowser) {
            browserIcon = deviceBrowser.toLowerCase()
            if (browserIcon == 'ie') browserIcon = 'internet-explorer'
        }
        browserVersion = '(Version: ' + ua.browser.version + ')'
    }

    var browserString = '<div class="timeline-device-browser"><span class="fa fa-stack">' +
        '<i class="fa fa-' + escapeHtml(browserIcon) + ' fa-stack-1x"></i></span> ' +
        deviceBrowser + ' ' + browserVersion + '</div>'

    detailsString += browserString

    // Show the IP address that the recipient connected from. Gophish records
    // this on each "Clicked Link" / "Submitted Data" event in browser.address.
    var ipAddress = (event_details.browser && event_details.browser['address']) ?
        event_details.browser['address'] : ''
    if (ipAddress) {
        var ipString = '<div class="timeline-device-ip"><span class="fa fa-stack">' +
            '<i class="fa fa-map-marker fa-stack-1x"></i></span> ' +
            'IP Address: ' + escapeHtml(ipAddress) + '</div>'
        detailsString += ipString
    }

    detailsString += '</div>'
    return detailsString
}

function renderTimeline(data) {
    record = {
        "id": data[0],
        "first_name": data[2],
        "last_name": data[3],
        "email": data[4],
        "position": data[5],
        "status": data[6],
        "reported": data[7],
        "send_date": data[8]
    }
    results = '<div class="timeline col-sm-12 well well-lg">' +
        '<h6>Timeline for ' + escapeHtml(record.first_name) + ' ' + escapeHtml(record.last_name) +
        '</h6><span class="subtitle">Email: ' + escapeHtml(record.email) +
        '<br>Result ID: ' + escapeHtml(record.id) + '</span>' +
        '<div class="timeline-graph col-sm-6">'
    $.each(campaign.timeline, function (i, event) {
        if (!event.email || event.email == record.email) {
            // Add the event
            results += '<div class="timeline-entry">' +
                '    <div class="timeline-bar"></div>'
            results +=
                '    <div class="timeline-icon ' + statuses[event.message].label + '">' +
                '    <i class="fa ' + statuses[event.message].icon + '"></i></div>' +
                '    <div class="timeline-message">' + escapeHtml(event.message) +
                '    <span class="timeline-date">' + moment.utc(event.time).local().format('MMMM Do YYYY h:mm:ss a') + '</span>'
            if (event.details) {
                details = JSON.parse(event.details)
                if (event.message == "Clicked Link" || event.message == "Submitted Data") {
                    deviceView = renderDevice(details)
                    if (deviceView) {
                        results += deviceView
                    }
                }
                if (event.message == "Submitted Data") {
                    results += '<div class="timeline-replay-button"><button onclick="replay(' + i + ')" class="btn btn-success">'
                    results += '<i class="fa fa-refresh"></i> Replay Credentials</button></div>'
                    results += '<div class="timeline-event-details"><i class="fa fa-caret-right"></i> View Details</div>'
                }
                if (details.payload) {
                    results += '<div class="timeline-event-results">'
                    results += '    <table class="table table-condensed table-bordered table-striped">'
                    results += '        <thead><tr><th>Parameter</th><th>Value(s)</tr></thead><tbody>'
                    // Record the source IP address alongside the submitted data
                    if (details.browser && details.browser['address']) {
                        results += '    <tr>'
                        results += '        <td>IP Address</td>'
                        results += '        <td>' + escapeHtml(details.browser['address']) + '</td>'
                        results += '    </tr>'
                    }
                    $.each(Object.keys(details.payload), function (i, param) {
                        if (param == "rid") {
                            return true;
                        }
                        results += '    <tr>'
                        results += '        <td>' + escapeHtml(param) + '</td>'
                        results += '        <td>' + escapeHtml(details.payload[param]) + '</td>'
                        results += '    </tr>'
                    })
                    results += '       </tbody></table>'
                    results += '</div>'
                }
                if (details.error) {
                    results += '<div class="timeline-event-details"><i class="fa fa-caret-right"></i> View Details</div>'
                    results += '<div class="timeline-event-results">'
                    results += '<span class="label label-default">Error</span> ' + details.error
                    results += '</div>'
                }
            }
            results += '</div></div>'
        }
    })
    // Add the scheduled send event at the bottom
    if (record.status == "Scheduled" || record.status == "Retrying") {
        results += '<div class="timeline-entry">' +
            '    <div class="timeline-bar"></div>'
        results +=
            '    <div class="timeline-icon ' + statuses[record.status].label + '">' +
            '    <i class="fa ' + statuses[record.status].icon + '"></i></div>' +
            '    <div class="timeline-message">' + "Scheduled to send at " + record.send_date + '</span>'
    }
    results += '</div></div>'
    return results
}

/* computeFunnel tallies the conversion funnel counts from the campaign
 * results. Each result is "backfilled" so that, e.g., a recipient who clicked
 * is also counted as having opened and been sent (matching gophish's progress
 * model). Reported is tracked independently via the result's reported flag.
 *
 * @param {object} c - a campaign results object
 * @returns {object} counts keyed by sent/opened/clicked/submitted/reported
 */
function computeFunnel(c) {
    var counts = { sent: 0, opened: 0, clicked: 0, submitted: 0, reported: 0 }
    var order = ["Email Sent", "Email Opened", "Clicked Link", "Submitted Data"]
    var keymap = {
        "Email Sent": "sent",
        "Email Opened": "opened",
        "Clicked Link": "clicked",
        "Submitted Data": "submitted"
    }
    $.each(c.results || [], function (i, r) {
        if (r.reported) {
            counts.reported++
        }
        var step = order.indexOf(r.status)
        if (step < 0) {
            return true
        }
        for (var k = 0; k <= step; k++) {
            counts[keymap[order[k]]]++
        }
    })
    return counts
}

/* buildDonut returns the HTML for an SVG ring chart with a centered label.
 *
 * @param {object[]} segments - [{value, color}] drawn clockwise
 * @param {string} centerTop - large centered text (e.g. "14.8%")
 * @param {string} centerSub - small caption under it (e.g. "COMPROMISED")
 */
function buildDonut(segments, centerTop, centerSub) {
    var size = 158, stroke = 17
    var r = (size - stroke) / 2
    var circ = 2 * Math.PI * r
    var total = segments.reduce(function (a, s) { return a + s.value }, 0) || 1
    var off = 0
    var arcs = ''
    $.each(segments, function (i, s) {
        var len = (s.value / total) * circ
        arcs += '<circle cx="' + (size / 2) + '" cy="' + (size / 2) + '" r="' + r + '"' +
            ' fill="none" stroke="' + s.color + '" stroke-width="' + stroke + '"' +
            ' stroke-dasharray="' + len + ' ' + (circ - len) + '"' +
            ' stroke-dashoffset="' + (-off) + '"></circle>'
        off += len
    })
    return '<div style="position:relative;width:' + size + 'px;height:' + size + 'px;">' +
        '<svg width="' + size + '" height="' + size + '" style="transform:rotate(-90deg)">' +
        '<circle cx="' + (size / 2) + '" cy="' + (size / 2) + '" r="' + r + '" fill="none"' +
        ' stroke="var(--panel-2)" stroke-width="' + stroke + '"></circle>' + arcs + '</svg>' +
        '<div style="position:absolute;inset:0;display:grid;place-items:center;text-align:center;">' +
        '<div><div class="num" style="font-size:30px;font-weight:600;letter-spacing:-1px;">' + centerTop + '</div>' +
        '<div class="mono" style="font-size:10.5px;color:var(--ink-dim);letter-spacing:0.5px;margin-top:2px;">' + centerSub + '</div>' +
        '</div></div></div>'
}

/* renderHeader fills in the campaign title, meta line and status pill.
 * The /results endpoint only returns id/name/status/results/timeline, so the
 * launch time is read from the "Campaign Created" event in the timeline. */
function renderHeader(c) {
    $("#page-title").text(c.name || "Results")
    var meta = []
    if (c.id) {
        meta.push("Campaign #" + c.id)
    }
    var created = null
    $.each(c.timeline || [], function (i, e) {
        if (e.message == "Campaign Created") {
            created = e.time
            return false
        }
    })
    if (created) {
        meta.push("launched " + moment.utc(created).local().format('YYYY-MM-DD HH:mm'))
    }
    $("#campaignMeta").text(meta.join("  \u00B7  "))

    var s = c.status || "Active"
    var pillClass = "pill-active"
    if (s == "Completed") {
        pillClass = "pill-done"
    }
    $("#campaignStatus").html('<span class="pill ' + pillClass + '"><span class="dot"></span>' + escapeHtml(s) + '</span>')
}

/* renderResultsCharts draws the conversion funnel and the outcome donut from
 * the live campaign data. Called on initial load and on every poll. */
function renderResultsCharts(c) {
    var recipients = (c.results || []).length
    var f = computeFunnel(c)

    /* ---- Conversion funnel ---- */
    var rows = [
        { label: "Email Sent", value: f.sent, color: "var(--c-sent)" },
        { label: "Email Opened", value: f.opened, color: "var(--c-opened)" },
        { label: "Clicked Link", value: f.clicked, color: "var(--c-clicked)" },
        { label: "Submitted Data", value: f.submitted, color: "var(--c-submitted)" },
        { label: "Reported", value: f.reported, color: "var(--c-reported)" }
    ]
    var base = rows[0].value || recipients || 1
    var funnelHtml = '<div class="funnel">'
    $.each(rows, function (i, d) {
        var pct = (d.value / base) * 100
        var ofPrev = i ? (d.value / (rows[i - 1].value || 1)) * 100 : 100
        funnelHtml += '<div class="funnel-row">' +
            '<div class="fl"><span class="sw" style="background:' + d.color + '"></span>' + d.label + '</div>' +
            '<div class="funnel-track"><div class="funnel-fill" style="width:' + Math.max(pct, 7).toFixed(0) + '%;background:' + d.color + '">' + pct.toFixed(0) + '%</div></div>' +
            '<div class="fv"><b class="num">' + d.value.toLocaleString() + '</b> <span class="num">' + (i ? ofPrev.toFixed(0) + '%' : '\u2014') + '</span></div>' +
            '</div>'
    })
    funnelHtml += '</div>'
    $("#resultsFunnel").html(funnelHtml)
    $("#funnelSub").text(recipients.toLocaleString() + " recipients")

    /* ---- Outcome donut ---- */
    var submitted = f.submitted
    var clickedOnly = Math.max(f.clicked - f.submitted, 0)
    var openedOnly = Math.max(f.opened - f.clicked, 0)
    var notOpened = Math.max(f.sent - f.opened, 0)
    var compromised = recipients ? (submitted / recipients) * 100 : 0
    $("#outcomeChart").html(buildDonut([
        { value: submitted, color: "var(--c-submitted)" },
        { value: clickedOnly, color: "var(--c-clicked)" },
        { value: openedOnly, color: "var(--c-opened)" },
        { value: notOpened, color: "var(--c-sent)" }
    ], compromised.toFixed(1) + "%", "COMPROMISED"))

    var legend = [
        ["Submitted", submitted, "var(--c-submitted)"],
        ["Clicked only", clickedOnly, "var(--c-clicked)"],
        ["Opened only", openedOnly, "var(--c-opened)"],
        ["Reported", f.reported, "var(--c-reported)"]
    ]
    var legendHtml = ''
    $.each(legend, function (i, row) {
        legendHtml += '<div class="soc-between">' +
            '<span style="display:flex;align-items:center;gap:8px;font-size:12.5px;color:var(--ink-mid);">' +
            '<span style="width:9px;height:9px;border-radius:3px;background:' + row[2] + ';"></span>' + row[0] + '</span>' +
            '<span class="num" style="font-weight:600;">' + row[1].toLocaleString() + '</span>' +
            '</div>'
    })
    $("#outcomeLegend").html(legendHtml)
}

/* renderGeo fills the "Top Sources" list and the map footer from the bubbles
 * (one per origin IP, with an event count) built in updateMap. */
function renderGeo() {
    var sorted = bubbles.slice().sort(function (a, b) { return b.count - a.count }).slice(0, 6)
    var max = sorted.length ? sorted[0].count : 1
    var html = ''
    $.each(sorted, function (i, b) {
        html += '<div class="gi"><span class="gn">' + escapeHtml(b.ip) + '</span>' +
            '<span class="gbar"><i style="width:' + ((b.count / max) * 100) + '%"></i></span>' +
            '<span class="gv">' + b.count + '</span></div>'
    })
    if (!html) {
        html = '<div class="mono" style="color:var(--ink-faint);font-size:12px;">No geolocated events yet</div>'
    }
    $("#geoList").html(html)

    var totalEvents = 0
    $.each(bubbles, function (i, b) { totalEvents += b.count })
    $("#geoFooter").text(
        totalEvents.toLocaleString() + " geolocated event" + (totalEvents == 1 ? "" : "s") +
        " \u00B7 " + bubbles.length + " source" + (bubbles.length == 1 ? "" : "s"))
}

/* Updates the bubbles on the map

@param {campaign.result[]} results - The campaign results to process
*/
var updateMap = function (results) {
    bubbles = []
    $.each(campaign.results, function (i, result) {
        // Check that it wasn't an internal IP
        if (result.latitude == 0 && result.longitude == 0) {
            return true;
        }
        newIP = true
        $.each(bubbles, function (i, bubble) {
            if (bubble.ip == result.ip) {
                bubbles[i].radius += 1
                bubbles[i].count += 1
                newIP = false
                return false
            }
        })
        if (newIP) {
            bubbles.push({
                latitude: result.latitude,
                longitude: result.longitude,
                name: result.ip,
                ip: result.ip,
                count: 1,
                fillKey: "point",
                radius: 2
            })
        }
    })
    // Mark each origin on the map and show the IP address (and how many
    // recipients connected from it) when hovering the bubble.
    if (map) {
        map.bubbles(bubbles, {
            popupTemplate: function (geo, data) {
                return '<div class="hoverinfo">' +
                    '<strong>IP Address:</strong> ' + escapeHtml(data.name) +
                    '<br><strong>Events:</strong> ' + escapeHtml(String(data.count)) +
                    '</div>'
            }
        })
    }
    // The "Top Sources" list and footer work from the same data, so they
    // render even when the visual map is disabled.
    renderGeo()
}

/**
 * Creates a status label for use in the results datatable
 * @param {string} status 
 * @param {moment(datetime)} send_date 
 */
function createStatusLabel(status, send_date) {
    var label = statuses[status].label || "label-default";
    var statusColumn = "<span class=\"label " + label + "\">" + status + "</span>"
    // Add the tooltip if the email is scheduled to be sent
    if (status == "Scheduled" || status == "Retrying") {
        var sendDateMessage = "Scheduled to send at " + send_date
        statusColumn = "<span class=\"label " + label + "\" data-toggle=\"tooltip\" data-placement=\"top\" data-html=\"true\" title=\"" + sendDateMessage + "\">" + status + "</span>"
    }
    return statusColumn
}

/* poll - Queries the API and updates the UI with the results
 *
 * Updates:
 * * Header (title / meta / status)
 * * Conversion Funnel + Outcome donut
 * * Map bubbles + Top Sources list
 * * Datatable
 */
function poll() {
    api.campaignId.results(campaign.id)
        .success(function (c) {
            campaign = c
            /* Refresh the header, conversion funnel and outcome donut */
            renderHeader(campaign)
            renderResultsCharts(campaign)

            /* Update the datatable */
            resultsTable = $("#resultsTable").DataTable()
            resultsTable.rows().every(function (i, tableLoop, rowLoop) {
                var row = this.row(i)
                var rowData = row.data()
                var rid = rowData[0]
                $.each(campaign.results, function (j, result) {
                    if (result.id == rid) {
                        rowData[8] = moment(result.send_date).format('MMMM Do YYYY, h:mm:ss a')
                        rowData[7] = result.reported
                        rowData[6] = result.status
                        resultsTable.row(i).data(rowData)
                        if (row.child.isShown()) {
                            $(row.node()).find("#caret").removeClass("fa-caret-right")
                            $(row.node()).find("#caret").addClass("fa-caret-down")
                            row.child(renderTimeline(row.data()))
                        }
                        return false
                    }
                })
            })
            resultsTable.draw(false)
            /* Update the map information */
            updateMap(campaign.results)
            $('[data-toggle="tooltip"]').tooltip()
            $("#refresh_message").hide()
            $("#refresh_btn").show()
        })
}

function load() {
    campaign.id = window.location.pathname.split('/').slice(-1)[0]
    api.campaignId.results(campaign.id)
        .success(function (c) {
            campaign = c
            if (campaign) {
                $("title").text(c.name + " - Gophish")
                $("#loading").hide()
                $("#campaignResults").show()
                // Set the title, meta line and status pill
                renderHeader(c)
                if (c.status == "Completed") {
                    $('#complete_button')[0].disabled = true;
                    $('#complete_button').text('Completed!');
                    doPoll = false;
                }
                // Setup viewing the details of a result
                $("#resultsTable").on("click", ".timeline-event-details", function () {
                    // Show the parameters
                    payloadResults = $(this).parent().find(".timeline-event-results")
                    if (payloadResults.is(":visible")) {
                        $(this).find("i").removeClass("fa-caret-down")
                        $(this).find("i").addClass("fa-caret-right")
                        payloadResults.hide()
                    } else {
                        $(this).find("i").removeClass("fa-caret-right")
                        $(this).find("i").addClass("fa-caret-down")
                        payloadResults.show()
                    }
                })
                // Setup the results table
                resultsTable = $("#resultsTable").DataTable({
                    destroy: true,
                    "order": [
                        [2, "asc"]
                    ],
                    columnDefs: [{
                            orderable: false,
                            targets: "no-sort"
                        }, {
                            className: "details-control",
                            "targets": [1]
                        }, {
                            "visible": false,
                            "targets": [0, 8]
                        },
                        {
                            "render": function (data, type, row) {
                                return createStatusLabel(data, row[8])
                            },
                            "targets": [6]
                        },
                        {
                            className: "text-center",
                            "render": function (reported, type, row) {
                                if (type == "display") {
                                    if (reported) {
                                        return "<i class='fa fa-check-circle text-center text-success'></i>"
                                    }
                                    return "<i role='button' class='fa fa-times-circle text-center text-muted' onclick='report_mail(\"" + row[0] + "\", \"" + campaign.id + "\");'></i>"
                                }
                                return reported
                            },
                            "targets": [7]
                        }
                    ]
                });
                resultsTable.clear();
                $.each(campaign.results, function (i, result) {
                    resultsTable.row.add([
                        result.id,
                        "<i id=\"caret\" class=\"fa fa-caret-right\"></i>",
                        escapeHtml(result.first_name) || "",
                        escapeHtml(result.last_name) || "",
                        escapeHtml(result.email) || "",
                        escapeHtml(result.position) || "",
                        result.status,
                        result.reported,
                        moment(result.send_date).format('MMMM Do YYYY, h:mm:ss a')
                    ])
                })
                resultsTable.draw();
                // Setup tooltips
                $('[data-toggle="tooltip"]').tooltip()
                // Setup the individual timelines
                $('#resultsTable tbody').on('click', 'td.details-control', function () {
                    var tr = $(this).closest('tr');
                    var row = resultsTable.row(tr);
                    if (row.child.isShown()) {
                        // This row is already open - close it
                        row.child.hide();
                        tr.removeClass('shown');
                        $(this).find("i").removeClass("fa-caret-down")
                        $(this).find("i").addClass("fa-caret-right")
                    } else {
                        // Open this row
                        $(this).find("i").removeClass("fa-caret-right")
                        $(this).find("i").addClass("fa-caret-down")
                        row.child(renderTimeline(row.data())).show();
                        tr.addClass('shown');
                    }
                });
                // Draw the conversion funnel and outcome donut
                renderResultsCharts(campaign)

                // Setup the geographic distribution map
                var mc = (window.SOC && window.SOC.map) ? window.SOC.map()
                    : { defaultFill: "#ffffff", point: "#283F50", border: "#283F50", highlight: "#1abc9c" }
                map = new Datamap({
                    element: document.getElementById("resultsMap"),
                    responsive: true,
                    fills: {
                        defaultFill: mc.defaultFill,
                        point: mc.point
                    },
                    geographyConfig: {
                        highlightFillColor: mc.highlight,
                        borderColor: mc.border
                    },
                    bubblesConfig: {
                        borderColor: mc.point
                    }
                });
                // Datamaps measures width on creation; if the container was
                // hidden it can render at 0px. Force a resize once visible.
                setTimeout(function () { if (map && map.resize) map.resize(); }, 50)
                updateMap(campaign.results)
            }
        })
        .error(function () {
            $("#loading").hide()
            errorFlash(" Campaign not found!")
        })
}

var setRefresh

function refresh() {
    if (!doPoll) {
        return;
    }
    $("#refresh_message").show()
    $("#refresh_btn").hide()
    poll()
    clearTimeout(setRefresh)
    setRefresh = setTimeout(refresh, 60000)
};

function report_mail(rid, cid) {
    Swal.fire({
        title: "Are you sure?",
        text: "This result will be flagged as reported (RID: " + rid + ")",
        type: "question",
        animation: false,
        showCancelButton: true,
        confirmButtonText: "Continue",
        confirmButtonColor: "#428bca",
        reverseButtons: true,
        allowOutsideClick: false,
        showLoaderOnConfirm: true
    }).then(function (result) {
        if (result.value){
            api.campaignId.get(cid).success((function(c) {
                report_url = new URL(c.url)
                report_url.pathname = '/report'
                report_url.search = "?rid=" + rid 
                fetch(report_url)
                .then(response => {
                    if (!response.ok) {
                        throw new Error(`HTTP error! Status: ${response.status}`);
                    }
                    refresh();
                })
                .catch(error => {
                    let errorMessage = error.message;
                    if (error.message === "Failed to fetch") {
                        errorMessage = "This might be due to Mixed Content issues or network problems.";
                    }
                    Swal.fire({
                        title: 'Error',
                        text: errorMessage,
                        type: 'error',
                        confirmButtonText: 'Close'
                    });
                });
            }));
        }
    })
}

$(document).ready(function () {
    Highcharts.setOptions({
        global: {
            useUTC: false
        }
    })
    load();

    // Start the polling loop
    setRefresh = setTimeout(refresh, 60000)
})
